graphql.query:
mutation LoginBySlug($slug: String!, $email: String!, $password: String!) {
  loginBySlug(slug: $slug, email: $email, password: $password) {
    accessToken
    refreshToken
  }
}

mutation LoginTenantUser($tenantId: String!, $email: String!, $password: String!) {
  loginTenantUser(tenantId: $tenantId, email: $email, password: $password) {
    accessToken
    refreshToken
  }
}

mutation LoginPlatformUser($email: String!, $password: String!) {
  loginPlatformUser(email: $email, password: $password) {
    accessToken
    refreshToken
  }
}

mutation RefreshToken($refreshToken: String!) {
  refreshToken(refreshToken: $refreshToken) {
    accessToken
    refreshToken
  }
}

query Tenants($pagination: PaginationInput) {
  tenants(pagination: $pagination) {
    edges {
      node {
        id
        name
        slug
        status
        settings
        createdAt
        updatedAt
      }
      cursor
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
    totalCount
  }
}

